#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char num[100005];
    while (T--) {
        scanf("%s", num);
        int len = strlen(num);
        int i;
        for (i = len - 1; i >= 0; --i) {
            if ((num[i] - '0') % 2 != 0) break; // odd digit found
        }
        if (i == -1) {
            printf("-1\n");
        } else {
            for (int j = 0; j <= i; ++j) putchar(num[j]);
            putchar('\n');
        }
    }
    return 0;
}

