int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        string num;
        cin >> num;
        int i = (int)num.size() - 1;
        while (i >= 0 && ((num[i] - '0') % 2 == 0)) --i; // skip even digits
        if (i == -1) cout << -1 << '\n';
        else cout << num.substr(0, i + 1) << '\n';
    }
    return 0;
}

