import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    idx = 1
    out = []
    for _ in range(T):
        num = data[idx]
        idx += 1
        # find last odd digit
        for i in range(len(num) - 1, -1, -1):
            if (ord(num[i]) - ord('0')) % 2 == 1:
                out.append(num[:i+1])
                break
        else:
            out.append('-1')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

